// Frontend: Leaderboard Component (src/components/Leaderboard.js)

import React, { useEffect, useState } from 'react';
import { Card } from "@/components/ui/card";

const Leaderboard = () => {
    const [leaderboard, setLeaderboard] = useState([]);

    useEffect(() => {
        fetch('http://localhost:5000/api/leaderboard')
            .then(response => response.json())
            .then(data => setLeaderboard(data))
            .catch(error => console.error('Error fetching leaderboard:', error));
    }, []);

    return (
        <div className="max-w-2xl mx-auto mt-10">
            <h2 className="text-xl font-bold mb-4">Codeforces Leaderboard</h2>
            {leaderboard.map((user, index) => (
                <Card key={index} className="p-4 mb-2 flex justify-between items-center border rounded-lg shadow">
                    <div>
                        <h3 className="font-semibold">{user.username}</h3>
                        <p className="text-sm text-gray-500">Rank: {user.rank} (Max: {user.maxRank})</p>
                    </div>
                    <div className="text-right">
                        <p className="font-bold">Rating: {user.rating}</p>
                        <p className="text-sm text-gray-500">Max: {user.maxRating}</p>
                    </div>
                </Card>
            ))}
        </div>
    );
};

export default Leaderboard;
